def histogram(test):
    """Given a string representing space-separated lowercase letters, return a dictionary
    with the letter that has the most repetition, containing the corresponding count.
    If several letters have the same occurrence, return all of them.

    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}
    """
    from collections import Counter

    # Split the input string into individual letters
    elements = test.split()

    # Count the occurrence of each letter
    counts = Counter(elements)

    # Find the maximum occurrence
    max_count = max(counts.values(), default=0)

    # Create a dictionary with letters having the maximum occurrence
    result = {letter: count for letter, count in counts.items() if count == max_count}

    return result

def minSubArraySum(nums):
    """
    Given an array of integers nums, find the minimum sum of any non-empty sub-array
    of nums.
    Example
    minSubArraySum([2, 3, 4, 1, 2, 4]) == 1
    minSubArraySum([-1, -2, -3]) == -6
    """
    if not nums:
        return 0

    current_min = nums[0]
    global_min = nums[0]

    for num in nums[1:]:
        if current_min > 0:
            current_min = num
        else:
            current_min += num

        if current_min < global_min:
            global_min = current_min

    return global_min

