def minPath(grid, k):
    from heapq import heappush, heappop

    N = len(grid)
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]  # Right, down, left, up

    def neighbors(r, c):
        for dr, dc in directions:
            nr, nc = r + dr, c + dc
            if 0 <= nr < N and 0 <= nc < N:
                yield nr, nc

    def lexicographical_min_path():
        # Priority queue item format: (current_path, current_row, current_col)
        pq = []
        for r in range(N):
            for c in range(N):
                heappush(pq, ([grid[r][c]], r, c))

        while pq:
            current_path, r, c = heappop(pq)

            if len(current_path) == k:
                return current_path

            for nr, nc in neighbors(r, c):
                new_path = current_path + [grid[nr][nc]]
                heappush(pq, (new_path, nr, nc))

    return lexicographical_min_path()

