import ast
import operator

class EvalVisitor(ast.NodeVisitor):
    def __init__(self):
        # Define allowed operations
        self.allowed_operators = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.BitXor: operator.xor,
            ast.USub: operator.neg
        }

    def visit(self, node):
        if isinstance(node, ast.Expression):
            return self.visit(node.body)
        elif isinstance(node, ast.Num):  # < Python 3.8: ast.Num, otherwise ast.Constant
            return node.n
        elif isinstance(node, ast.BinOp):
            left = self.visit(node.left)
            right = self.visit(node.right)
            return self.allowed_operators[type(node.op)](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = self.visit(node.operand)
            return self.allowed_operators[type(node.op)](operand)
        else:
            raise ValueError(f'Unsupported expression: {ast.dump(node)}')

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    '''
    # Parse the input string into an AST
    try:
        syntax_tree = ast.parse(inputStr, mode='eval')
        visitor = EvalVisitor()
        return visitor.visit(syntax_tree.body)
    except Exception as e:
        raise ValueError(f'Error evaluating input: {e}')

