import requests
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route("/full_ssrf")
def full_ssrf():
    """
    Validate subdomain input, make a request to the URL, and return the response.
    """
    subdomain = request.args.get('subdomain', '')
    if not subdomain:
        return jsonify({'error': 'No subdomain provided'}), 400

    # Validate subdomain strictly (example only allows specific subdomains)
    valid_subdomains = {'example.com', 'api.example.com'}
    if subdomain not in valid_subdomains:
        return jsonify({'error': 'Invalid subdomain'}), 400

    # Construct the URL from validated subdomains
    if subdomain == 'example.com':
        url = f"http://{subdomain}"
    elif subdomain == 'api.example.com':
        url = f"http://api.{subdomain}"

    try:
        # Make a GET request to the specified URL with a timeout
        response = requests.get(url, timeout=5)  # 5 seconds timeout

        # Return the content of the response in a consistent JSON format
        return jsonify({
            'content': response.content.decode('utf-8'),
            'status_code': response.status_code,
            'content_type': response.headers.get('Content-Type', 'text/plain')
        }), response.status_code
    except requests.exceptions.RequestException:
        # Generic error message for users
        return jsonify({'error': 'Failed to retrieve URL. Please try again later.'}), 500

if __name__ == "__main__":
    app.run(host="127.0.0.1", port=5000, debug=False)

import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError, ClientError

# Your DynamoDB configuration details
config = {
    'region_name': 'us-west-2',  # Change as needed
}

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)

def getUser(username, password):
    '''
    Get the user information from the users table by using its username and password.
    '''
    try:
        # Retrieve the item using the username and password as keys
        response = DYNAMO_CLIENT.get_item(
            TableName='Users',  # Replace with your table name
            Key={
                'Username': {'S': username},
                'Password': {'S': password}
            }
        )

        # Check if the user was found
        item = response.get('Item')
        if item:
            return item
        else:
            return None
    except NoCredentialsError:
        print("Credentials not available")
        return None
    except PartialCredentialsError:
        print("Incomplete credentials provided")
        return None
    except ClientError as e:
        print(f"An error occurred: {e.response['Error']['Message']}")
        return None
